#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int hearts[K];
        for (int i = 0; i < K; i++) {
            scanf("%d", &hearts[i]);
        }
        double expectedValue = 0;
        int totalRectangles = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                for (int k = i; k < N; k++) {
                    for (int l = j; l < M; l++) {
                        int rectangleHearts = 0;
                        for (int m = 0; m < K; m++) {
                            int heartX = (hearts[m] - 1) % M;
                            int heartY = (hearts[m] - 1) / M;
                            if (heartX >= j && heartX <= l && heartY >= i && heartY <= k) {
                                rectangleHearts++;
                            }
                        }
                        expectedValue += rectangleHearts;
                        totalRectangles++;
                    }
                }
            }
        }
        printf("%.9f\n", expectedValue / totalRectangles);
    }
    return 0;
}

